import time
import asyncio
from typing import Dict, List, Optional, Tuple, Any, Union, TYPE_CHECKING
from dataclasses import dataclass, asdict
from enum import Enum

if TYPE_CHECKING:
    from .config import Config

# Import all quality components
from .quality_recovery_engine import QualityRecoveryEngine, QualityMetrics, ResponseTier, InputComplexity, FastPathConfig
from .instant_hook_engine import InstantHookEngine, HookMatch, HookType
from .rag_feedback_engine import RAGFeedbackEngine, FeedbackEntry, FeedbackType
from .adaptive_workflow_engine import AdaptiveWorkflowEngine

@dataclass
class MasterQualityMetrics:
    """Comprehensive quality metrics combining all systems"""
    # Response metrics
    total_queries: int = 0
    instant_responses: int = 0
    standard_responses: int = 0
    observer_responses: int = 0

    # Performance metrics
    average_response_time: float = 0.0
    instant_coverage_rate: float = 0.0
    quality_score: float = 0.0

    # Learning metrics
    hooks_learned: int = 0
    feedback_entries: int = 0
    rag_optimization_score: float = 0.0

    # System health
    fallback_rate: float = 0.0
    errors_count: int = 0
    error_rate: float = 0.0
    user_satisfaction: float = 0.0

class SystemMode(Enum):
    """System operation modes"""
    PERFORMANCE_FIRST = "performance_first"   # Prioritize speed over features
    BALANCED = "balanced"                     # Balance speed and features
    FEATURE_RICH = "feature_rich"            # Use all available features
    LEARNING = "learning"                    # Focus on learning and optimization

class MasterQualitySystem:
    """Master system coordinating all quality enhancement components"""

    def __init__(self, config: Optional[Union["Config", Dict[str, Any]]] = None):
        # Handle both Config dataclass and Dict types
        if config is None:
            self.config = {}
        elif hasattr(config, '__dict__'):  # Config dataclass
            self.config = config
        else:  # Dict
            self.config = config

        # Initialize all subsystems
        self.quality_engine = QualityRecoveryEngine(FastPathConfig(
            enable_fast_path=True,
            instant_response_threshold=0.5,
            complexity_analysis_threshold=10,
            rag_activation_threshold=0.6,
            observer_activation_threshold=0.7
        ))

        self.hook_engine = InstantHookEngine()
        # Initialize with minimal dependencies
        try:
            from .quant_manager import DynamicQuantizationManager
            quant_manager = DynamicQuantizationManager()
            self.adaptive_workflow_engine = AdaptiveWorkflowEngine(quant_manager, self.config)
        except Exception as e:
            print(f"[Quality][WARN] AdaptiveWorkflowEngine init failed: {e}")
            self.adaptive_workflow_engine = None

        # RAGFeedbackEngine() has no required args in our codebase
        # (see rag_feedback_engine.py), so construct directly.
        self.rag_engine = RAGFeedbackEngine()
        self.workflow_engine = None  # Initialized when needed

        # System state
        self.mode = SystemMode.BALANCED
        self.master_metrics = MasterQualityMetrics()
        self.interaction_history = []

        # Performance tracking
        self.response_times = []
        self.quality_scores = []

    async def process_user_input(self, user_input: str, interactive_instance,
                                context: Optional[Dict[str, Any]] = None) -> Tuple[str, Dict[str, Any]]:
        """Main entry point - processes user input through the complete quality system"""

        start_time = time.time()
        context = context or {}

        try:
            # Step 1: Instant Hook Recognition (highest priority)
            hook_match = self.hook_engine.recognize_instant_pattern(user_input)
            if hook_match:
                response = hook_match.instant_response
                response_tier = ResponseTier.INSTANT
                processing_time = time.time() - start_time

                # Record instant success
                self._record_interaction(user_input, response, response_tier, processing_time,
                                       hook_used=hook_match.hook.hook_id, context=context)

                # Still analyze for feedback learning
                self._analyze_for_feedback_learning(user_input, response, context)

                return response, self._create_response_metadata(response_tier, processing_time, hook_match.hook.hook_id)

            # Step 2: Quality Recovery Three-Tier System
            response, metrics = await self.quality_engine.process_input_with_quality_recovery(
                user_input, interactive_instance, context=context
            )

            # Push structured interaction into RAG engine
            try:
                # The response is a string from quality recovery
                assistant_response = response
                rag_active = bool(context.get("rag_active", False))
                tools_used = list(context.get("tools_used", []))
                self.rag_engine.add_interaction_context(
                    user_input=user_input,
                    assistant_response=assistant_response,
                    rag_active=rag_active,
                    tools_used=tools_used,
                )
            except Exception as e:
                print(f"[Quality][WARN] RAG feedback add_interaction_context failed: {e}")

            # Create response metadata from metrics
            processing_time = time.time() - start_time
            response_metadata = self._create_response_metadata(
                metrics.tier_used, processing_time, None, metrics
            )

            return response, response_metadata

        except Exception as e:
            # Fallback processing
            fallback_response = f"I apologize, but I encountered an error processing your request: {str(e)[:100]}"
            processing_time = time.time() - start_time

            self._record_error(user_input, str(e), processing_time)

            return fallback_response, self._create_response_metadata(
                ResponseTier.STANDARD, processing_time, error=str(e)
            )

    def _analyze_for_feedback_learning(self, user_input: str, response: str, context: Dict[str, Any]):
        """Analyze interaction for potential feedback learning"""

        # Add to feedback engine context
        self.feedback_engine.add_interaction_context(
            user_input, response,
            context.get('rag_active', False),
            context.get('tools_used', [])
        )

        # Check if this might be feedback to previous interaction
        feedback_entry = self.feedback_engine.analyze_user_feedback(user_input, context)
        if feedback_entry:
            # Learn from feedback
            self._apply_feedback_learning(feedback_entry)

    def _apply_feedback_learning(self, feedback_entry: FeedbackEntry):
        """Apply learning from user feedback"""

        # Update master metrics
        self.master_metrics.feedback_entries += 1

        # Apply feedback to hook learning
        if feedback_entry.feedback_type == FeedbackType.POSITIVE_CONFIRMATION:
            # Positive feedback - could create new hook if pattern emerges
            self.hook_engine.usage_history.append({
                'timestamp': feedback_entry.timestamp,
                'input': feedback_entry.user_input,
                'feedback': 'positive',
                'success': True
            })

        elif feedback_entry.feedback_type == FeedbackType.NEGATIVE_DENIAL:
            # Negative feedback - learn what patterns to avoid
            if feedback_entry.context_window:
                self._learn_from_failure(feedback_entry)

    def _learn_from_failure(self, feedback_entry: FeedbackEntry):
        """Learn from negative feedback to improve future responses"""

        # Analyze what went wrong
        if feedback_entry.context_window:
            failed_interaction = feedback_entry.context_window[-1]

            # If we used a hook that got negative feedback, reduce its confidence
            for hook_id, hook in self.hook_engine.hooks.items():
                if (isinstance(failed_interaction, dict) and
                    hook_id in str(failed_interaction.get('hook_used', ''))):
                    hook.success_rate *= 0.9  # Reduce success rate
                    hook.confidence *= 0.95   # Reduce confidence

    async def _post_process_response(self, user_input: str, response: str,
                                   quality_metrics: QualityMetrics,
                                   context: Dict[str, Any]) -> str:
        """Post-process response based on system mode and context"""

        # In learning mode, we might add metadata to responses
        if self.mode == SystemMode.LEARNING:
            # Add subtle learning indicators
            if quality_metrics.tier_used == ResponseTier.INSTANT:
                # Don't modify instant responses
                pass
            elif quality_metrics.bypass_activated:
                # Response used bypass - good for performance
                pass

        # Check if we should request feedback
        if self.feedback_engine.should_request_feedback():
            # Subtle feedback request
            if len(response) < 500:  # Only for shorter responses
                response += "\n\n*Is this helpful?*"

        return response

    def _record_interaction(self, user_input: str, response: str, tier: ResponseTier,
                          processing_time: float, hook_used: str = None,
                          context: Dict[str, Any] = None):
        """Record interaction for analytics and learning"""

        interaction = {
            'timestamp': time.time(),
            'user_input': user_input,
            'response': response,
            'tier': tier.value,
            'processing_time': processing_time,
            'hook_used': hook_used,
            'context': context or {}
        }

        self.interaction_history.append(interaction)

        self.master_metrics.total_queries += 1
        # after updating totals:
        self.master_metrics.error_rate = (
            self.master_metrics.errors_count / max(1, self.master_metrics.total_queries)
        )

        if tier == ResponseTier.INSTANT:
            self.master_metrics.instant_responses += 1
        elif tier == ResponseTier.STANDARD:
            self.master_metrics.standard_responses += 1
        elif tier == ResponseTier.OBSERVER:
            self.master_metrics.observer_responses += 1

        # Update performance metrics
        self.response_times.append(processing_time)
        if len(self.response_times) > 100:
            self.response_times = self.response_times[-50:]

        self.master_metrics.average_response_time = sum(self.response_times) / len(self.response_times)
        self.master_metrics.instant_coverage_rate = (
            self.master_metrics.instant_responses / max(1, self.master_metrics.total_queries)
        )

    def _record_error(self, user_input: str, error: str, processing_time: float):
        """Record system error for analysis"""

        self.master_metrics.total_queries += 1
        self.master_metrics.errors_count += 1
        self.master_metrics.error_rate = (
            self.master_metrics.errors_count / self.master_metrics.total_queries
        )

        # Record error details
        error_record = {
            'timestamp': time.time(),
            'user_input': user_input,
            'error': error,
            'processing_time': processing_time
        }

        # Could implement error learning here

    def _create_response_metadata(self, tier: ResponseTier, processing_time: float,
                                hook_id: str = None, quality_metrics: QualityMetrics = None,
                                error: str = None) -> Dict[str, Any]:
        """Create metadata for response analysis"""

        metadata = {
            'tier': tier.value,
            'processing_time': processing_time,
            'timestamp': time.time()
        }

        if hook_id:
            metadata['hook_used'] = hook_id

        if quality_metrics:
            metadata.update({
                'bypass_activated': quality_metrics.bypass_activated,
                'rag_activated': quality_metrics.rag_activated,
                'observer_activated': quality_metrics.observer_activated,
                'quality_score': quality_metrics.quality_score
            })

        if error:
            metadata['error'] = error

        return metadata

    def get_system_status(self) -> Dict[str, Any]:
        """Get comprehensive system status and performance metrics"""

        # Get subsystem metrics
        hook_stats = self.hook_engine.get_instant_coverage_stats() if hasattr(self.hook_engine, 'get_instant_coverage_stats') else {}
        quality_summary = self.quality_engine.get_performance_summary()
        rag_recommendations = self.rag_feedback_engine.get_rag_optimization_recommendations() if hasattr(self.rag_feedback_engine, 'get_rag_optimization_recommendations') else {}

        return {
            'master_metrics': asdict(self.master_metrics),
            'system_mode': self.mode.value,
            'hook_engine': hook_stats,
            'quality_engine': quality_summary,
            'feedback_engine': {
                'overall_score': rag_recommendations.get('overall_score', 0),
                'feedback_summary': rag_recommendations.get('feedback_summary', {}),
                'priority_actions': rag_recommendations.get('priority_actions', [])
            },
            'recent_performance': {
                'avg_response_time': self.master_metrics.average_response_time,
                'instant_coverage': self.master_metrics.instant_coverage_rate,
                'error_rate': self.master_metrics.error_rate
            }
        }

    def optimize_system(self) -> Dict[str, Any]:
        """Perform system optimization based on collected metrics"""

        optimizations_applied = []

        # Optimize hook engine
        if self.master_metrics.total_queries > 50 and hasattr(self.hook_engine, 'learn_new_patterns'):
            new_hooks = self.hook_engine.learn_new_patterns()
            if new_hooks > 0:
                optimizations_applied.append(f"Learned {new_hooks} new instant patterns")
                self.master_metrics.hooks_learned += new_hooks

        # Optimize based on RAG feedback
        rag_recommendations = self.feedback_engine.get_rag_optimization_recommendations()
        for action in rag_recommendations.get('priority_actions', [])[:2]:  # Apply top 2
            optimizations_applied.append(f"RAG: {action}")

        # Adjust system mode based on performance
        if self.master_metrics.average_response_time > 2.0 and self.mode != SystemMode.PERFORMANCE_FIRST:
            self.mode = SystemMode.PERFORMANCE_FIRST
            optimizations_applied.append("Switched to performance-first mode")
        elif (self.master_metrics.instant_coverage_rate > 0.8 and
              self.master_metrics.average_response_time < 1.0 and
              self.mode != SystemMode.FEATURE_RICH):
            self.mode = SystemMode.FEATURE_RICH
            optimizations_applied.append("Switched to feature-rich mode")

        return {
            'optimizations_applied': optimizations_applied,
            'new_system_mode': self.mode.value,
            'performance_improvement_expected': len(optimizations_applied) > 0
        }

    def set_mode(self, mode: str):
        """Set system operation mode"""
        try:
            self.mode = SystemMode(mode)

            # Adjust subsystem parameters based on mode
            if self.mode == SystemMode.PERFORMANCE_FIRST:
                self.quality_engine.config.instant_response_threshold = 1.0
                self.quality_engine.config.rag_activation_threshold = 0.8
            elif self.mode == SystemMode.FEATURE_RICH:
                self.quality_engine.config.instant_response_threshold = 0.3
                self.quality_engine.config.rag_activation_threshold = 0.4
            elif self.mode == SystemMode.LEARNING:
                self.hook_engine.learning_enabled = True
                self.hook_engine.min_pattern_frequency = 2

        except ValueError:
            raise ValueError(f"Invalid mode: {mode}. Valid modes: {[m.value for m in SystemMode]}")


# Testing function
async def test_master_quality_system():
    """Test the complete integrated quality system"""

    class MockInteractive:
        """Mock interactive instance for testing"""
        class MockConfig:
            class MockRuntime:
                resources = 50
            class MockModel:
                name = "test_model"
            runtime = MockRuntime()
            model = MockModel()

        class MockClient:
            async def generate(self, **kwargs):
                await asyncio.sleep(0.1)
                return f"Generated response to: {kwargs.get('prompt', 'unknown')}"

        def __init__(self):
            self.config = self.MockConfig()
            self.ollama_client = self.MockClient()

        async def _generate_with_resources(self, prompt, **kwargs):
            await asyncio.sleep(0.3)
            return f"Resource-aware response to: {prompt}"

    print("🧪 Testing Master Quality System\n")

    # Initialize master system
    master_system = MasterQualitySystem()
    mock_interactive = MockInteractive()

    # Test cases covering all system tiers
    test_cases = [
        ("hi", "Instant hook response"),
        ("2+2", "Math hook response"),
        ("What is Python?", "Standard processing"),
        ("Analyze this complex data and create a comprehensive report", "Observer pattern"),
        ("thanks", "Positive feedback learning"),
        ("that's wrong", "Negative feedback learning"),
        ("show me evidence", "Evidence request feedback"),
        ("I don't understand", "Clarification request"),
    ]

    print("📊 Processing Test Cases:")
    print("=" * 80)

    total_time = 0
    for i, (test_input, description) in enumerate(test_cases):
        start_time = time.time()

        response, metadata = await master_system.process_user_input(
            test_input, mock_interactive,
            context={'rag_active': i % 3 == 0, 'tools_used': ['test_tool']}
        )

        processing_time = time.time() - start_time
        total_time += processing_time

        print(f"Input: {test_input}")
        print(f"Description: {description}")
        print(f"Response: {response[:60]}{'...' if len(response) > 60 else ''}")
        print(f"Tier: {metadata['tier']}")
        print(f"Processing Time: {processing_time:.3f}s")
        if 'hook_used' in metadata:
            print(f"Hook Used: {metadata['hook_used']}")
        print("-" * 80)

    # System optimization
    print("\n🔧 System Optimization:")
    optimization_result = master_system.optimize_system()
    print(f"Optimizations Applied: {len(optimization_result['optimizations_applied'])}")
    for opt in optimization_result['optimizations_applied']:
        print(f"  • {opt}")

    # System status
    print(f"\n📈 System Status:")
    status = master_system.get_system_status()
    print(f"Total Queries: {status['master_metrics']['total_queries']}")
    print(f"Instant Responses: {status['master_metrics']['instant_responses']}")
    print(f"Instant Coverage: {status['master_metrics']['instant_coverage_rate']:.1%}")
    print(f"Average Response Time: {status['master_metrics']['average_response_time']:.3f}s")
    print(f"System Mode: {status['system_mode']}")

    print(f"\n🎯 Hook Engine Performance:")
    print(f"Total Hook Count: {status['hook_engine']['hook_count']}")
    print(f"Instant Rate: {status['hook_engine']['instant_rate']:.1%}")

    print(f"\n📊 Quality Engine Performance:")
    for tier, stats in status['quality_engine'].items():
        print(f"{tier.title()}: {stats['count']} queries, {stats['avg_response_time']:.3f}s avg")

    print(f"\n🧠 Feedback Engine:")
    feedback_stats = status['feedback_engine']['feedback_summary']
    print(f"Positive Rate: {feedback_stats.get('positive_rate', 0):.1%}")
    print(f"Negative Rate: {feedback_stats.get('negative_rate', 0):.1%}")

    if status['feedback_engine']['priority_actions']:
        print(f"\n🚨 Priority Actions:")
        for action in status['feedback_engine']['priority_actions']:
            print(f"  • {action}")

    print(f"\n⚡ Overall Performance:")
    print(f"Total Processing Time: {total_time:.3f}s")
    print(f"Average Per Query: {total_time/len(test_cases):.3f}s")
    print(f"Quality System Ready for Integration! ✅")


if __name__ == "__main__":
    asyncio.run(test_master_quality_system())